pub fn rotate_right<T: Clone>(arr: &mut [T], k: usize) {
    if arr.is_empty() {
        return;
    }

    let n = arr.len();
    let k = k % n;

    if k == 0 {
        return;
    }

    let mut temp = Vec::with_capacity(k);
    for i in (n - k)..n {
        temp.push(arr[i].clone());
    }

    for i in (k..n).rev() {
        arr[i] = arr[i - k].clone();
    }

    for i in 0..k {
        arr[i] = temp[i].clone();
    }
}

